function applyEffect(card,playerIndex){let skip=0,color=card.color;if(card.color==="wild")color=pickColor(gameState.players[playerIndex].hand);gameState.currentColor=color;gameState.currentCard=copyCard(card);gameState.discardPile.push(copyCard(card));gameState.stats.colorPlays[card.color]=(gameState.stats.colorPlays[card.color]||0)+1;if(card.type==="action"){gameState.stats.actionCardsPlayed+=1;gameState.stats.specialPlays[card.value]+=1;if(card.value==="skip"){skip=1;gameState.stats.skipsCaused+=1;}if(card.value==="reverse"){if(gameState.players.length===2){skip=1;gameState.stats.skipsCaused+=1;}else gameState.direction*=-1;}if(card.value==="draw2"){const target=nextIndex(playerIndex,1);drawCards(target,2,`${gameState.players[playerIndex].name} uso +2`);gameState.stats.drawPenaltiesCaused+=2;if(target===0)gameState.stats.drawPenaltiesTaken+=2;skip=1;}}if(card.type==="wild"){gameState.stats.wildCardsPlayed+=1;gameState.stats.specialPlays[card.value]+=1;if(card.value==="wild4"){const target=nextIndex(playerIndex,1);drawCards(target,4,`${gameState.players[playerIndex].name} uso +4`);gameState.stats.drawPenaltiesCaused+=4;if(target===0)gameState.stats.drawPenaltiesTaken+=4;skip=1;}}return{skip,color};}
function playCard(playerIndex,cardId){const player=gameState.players[playerIndex],card=player.hand.find(c=>c.id===cardId);if(!card||!isPlayable(card)||gameState.over)return false;player.hand=player.hand.filter(c=>c.id!==cardId);gameState.stats.cardsPlayed+=1;gameState.stats.turnsTaken+=1;if(player.bot||demoMode)gameState.stats.botTurns+=1;gameState.turnCounter+=1;gameState.drawnThisTurn=false;gameState.drawnCardId=null;const effect=applyEffect(card,playerIndex);addJournal(`${player.name} juega ${cardLabel(card)} ${card.color==="wild"?`y canta ${colorLabel(effect.color)}`:`(${colorLabel(effect.color)})`}.`,card.type==="number"?"normal":"accent");if(player.hand.length===1){gameState.stats.unoCalls+=1;addJournal(`${player.name} canta UNO.`,"warning");playTone("uno");}if(player.hand.length===0){finalizeRound(playerIndex,`Ronda cerrada por ${playerIndex===0?"ti":player.name}.`);return true;}gameState.turnIndex=nextIndex(playerIndex,1+effect.skip);addReplay(`${player.name} jugo ${cardLabel(card)}.`);renderAll();persistSession();queueTurn();playTone(card.type==="number"?"play":"special");return true;}
function passTurn(){if(gameState.over||currentPlayer().bot)return;gameState.stats.turnsTaken+=1;gameState.turnCounter+=1;gameState.drawnThisTurn=false;gameState.drawnCardId=null;addJournal("Tu turno termina sin jugar carta.","warning");gameState.turnIndex=nextIndex(gameState.turnIndex,1);addReplay("Turno pasado tras robar.");renderAll();persistSession();queueTurn();}
function drawHuman(){if(gameState.over||replayMode||gamePaused||demoMode||currentPlayer().bot)return;pushUndo("Antes de robar");const drawn=drawCards(0,1,"turno normal");if(!drawn.length){gameState.drawnThisTurn=true;gameState.drawnCardId=null;addJournal("No quedan cartas disponibles para robar. Puedes pasar turno.","warning");addReplay("Intento de robo sin cartas disponibles.");renderAll();persistSession();setStatus("No quedan cartas para robar. Pulsa de nuevo para pasar.");return;}gameState.drawnThisTurn=true;gameState.drawnCardId=drawn[0]?.id||null;if(drawn[0])addJournal(`Robas ${cardLabel(drawn[0])}.`,"draw");addReplay("Carta robada.");renderAll();persistSession();setStatus(drawn[0]&&isPlayable(drawn[0])?"La carta robada se puede jugar o puedes pasar.":"No se puede jugar. Pulsa de nuevo para pasar.");}
function chooseBotCard(player){const cards=player.hand.filter(card=>isPlayable(card));if(!cards.length)return null;cards.sort((a,b)=>scoreBotCard(b)-scoreBotCard(a));return cards[0];}
function scoreBotCard(card){if(card.value==="wild4")return 100;if(card.value==="draw2")return 90;if(card.value==="skip")return 80;if(card.value==="reverse")return 70;if(card.value==="wild")return 60;return Number(card.value)||0;}
function botTurn(){if(!gameState||gameState.over||replayMode||gamePaused)return;const player=currentPlayer();if(!player.bot&&!demoMode)return;const acting=player.bot?player:gameState.players[0],card=chooseBotCard(acting);if(card){playCard(gameState.turnIndex,card.id);return;}const drawnCards=drawCards(gameState.turnIndex,1,`${acting.name} no tenia jugada`),drawn=drawnCards[drawnCards.length-1];if(drawn&&isPlayable(drawn)){playCard(gameState.turnIndex,drawn.id);return;}gameState.stats.turnsTaken+=1;gameState.turnCounter+=1;addJournal(drawn?`${acting.name} roba y pasa turno.`:`${acting.name} no puede robar y pasa turno.`,"warning");gameState.turnIndex=nextIndex(gameState.turnIndex,1);addReplay(drawn?`${acting.name} paso turno.`:`${acting.name} paso turno sin cartas para robar.`);renderAll();persistSession();queueTurn();}
function queueTurn(){if(!gameState||gameState.over||replayMode||gamePaused)return;renderActionButton();const player=currentPlayer();setStatus(`Turno de ${player.name}. Color activo: ${colorLabel(gameState.currentColor)}.`);if(demoMode||player.bot){const sid=gameSessionId;setTimeout(()=>{if(sid!==gameSessionId)return;botTurn();},demoMode?380:700);}}
function startTimer(){stopTimer();realGameTimerStartedAt=Date.now();gameState&&(gameState.pausedMs=0);gamePaused=false;renderTimer();gameTimerInterval=setInterval(()=>{if(!gameState||gameState.over||gamePaused||replayMode)return;renderTimer();},250);}
function stopTimer(){if(gameTimerInterval){clearInterval(gameTimerInterval);gameTimerInterval=null;}}
function togglePause(){if(!gameState||gameState.over||replayMode||demoMode)return;gamePaused=!gamePaused;if(gamePaused){gameState.pausedMs=nowMs();}else{realGameTimerStartedAt=Date.now()-(gameState.pausedMs||0);}els.pauseOverlay?.classList.toggle("hidden",!gamePaused);if(els.pause)els.pause.textContent=gamePaused?"SEGUIR":"PAUSA";setStatus(gamePaused?"Partida en pausa.":`Turno de ${currentPlayer().name}.`);}
function buildStatsText(){return["Estadisticas Finales de UNO Angeloso","",`Modo: ${gameState.modeLabel}`,`Puntuacion: ${gameState.score}`,`Record local: ${gameState.bestScore}`,`Tiempo real: ${elapsed(nowMs())}`,`Ganador: ${gameState.winner==null?"-":gameState.players[gameState.winner].name}`,`Turnos: ${gameState.stats.turnsTaken}`,`Cartas jugadas: ${gameState.stats.cardsPlayed}`,`Cartas robadas: ${gameState.stats.cardsDrawn}`,`Acciones jugadas: ${gameState.stats.actionCardsPlayed}`,`Comodines jugados: ${gameState.stats.wildCardsPlayed}`,`UNO cantados: ${gameState.stats.unoCalls}`,`Skips causados: ${gameState.stats.skipsCaused}`,`Penalizaciones causadas: ${gameState.stats.drawPenaltiesCaused}`,`Penalizaciones recibidas: ${gameState.stats.drawPenaltiesTaken}`,`Mano mas larga: ${gameState.stats.longestHand}`,"","Bitacora destacada",...(gameState.journalEntries.slice(0,12).map(e=>`- ${e.elapsedText} · ${e.text}`)||["- Sin eventos"])].join("\n");}
function renderStats(){if(!els.statsContent||!gameState||!statsPanelOpen)return;els.statsEyebrow&&(els.statsEyebrow.textContent=gameState.over?"Resumen final":"Tiempo real");els.shareText&&(els.shareText.value=buildStatsText());els.shareStats?.classList.toggle("hidden",!gameState.over);const turns=Math.max(1,gameState.stats.turnsTaken),ppt=(gameState.score/turns).toFixed(1),human=gameState.players[0];const colors=Object.entries(gameState.stats.colorPlays).map(([c,n])=>`<div class="stats-list-row"><span>${colorLabel(c)}</span><span>${n}</span></div>`).join("");const specials=Object.entries(gameState.stats.specialPlays).map(([k,n])=>`<div class="stats-list-row"><span>${esc(cardLabel({value:k,type:k.startsWith("wild")?"wild":"action"}))}</span><span>${n}</span></div>`).join("");els.statsContent.innerHTML=`<div class="stats-grid"><div class="stats-card"><span class="stats-card-label">Modo</span><span class="stats-card-value">${esc(gameState.modeLabel)}</span></div><div class="stats-card"><span class="stats-card-label">Puntuacion</span><span class="stats-card-value">${gameState.score}</span></div><div class="stats-card"><span class="stats-card-label">Tiempo real</span><span class="stats-card-value">${elapsed(nowMs())}</span></div><div class="stats-card"><span class="stats-card-label">Turnos</span><span class="stats-card-value">${gameState.stats.turnsTaken}</span></div><div class="stats-card"><span class="stats-card-label">Cartas jugadas</span><span class="stats-card-value">${gameState.stats.cardsPlayed}</span></div><div class="stats-card"><span class="stats-card-label">Cartas robadas</span><span class="stats-card-value">${gameState.stats.cardsDrawn}</span></div><div class="stats-card"><span class="stats-card-label">Puntos por turno</span><span class="stats-card-value">${ppt}</span></div><div class="stats-card"><span class="stats-card-label">Tu mano</span><span class="stats-card-value">${human.hand.length}</span></div></div><div class="stats-section"><h4>Presion de la mesa</h4><div class="stats-summary-grid"><div class="stats-summary-row"><span>Acciones jugadas</span><strong>${gameState.stats.actionCardsPlayed}</strong></div><div class="stats-summary-row"><span>Comodines jugados</span><strong>${gameState.stats.wildCardsPlayed}</strong></div><div class="stats-summary-row"><span>Skips causados</span><strong>${gameState.stats.skipsCaused}</strong></div><div class="stats-summary-row"><span>Penalizaciones causadas</span><strong>${gameState.stats.drawPenaltiesCaused}</strong></div><div class="stats-summary-row"><span>Penalizaciones recibidas</span><strong>${gameState.stats.drawPenaltiesTaken}</strong></div><div class="stats-summary-row"><span>UNO cantados</span><strong>${gameState.stats.unoCalls}</strong></div><div class="stats-summary-row"><span>Mano mas larga</span><strong>${gameState.stats.longestHand}</strong></div><div class="stats-summary-row"><span>Turns bots</span><strong>${gameState.stats.botTurns}</strong></div></div></div><div class="stats-section"><h4>Colores jugados</h4><div class="stats-list">${colors}</div></div><div class="stats-section"><h4>Especiales usadas</h4><div class="stats-list">${specials}</div></div>`;}
function loadRecords(v=Number(els.mode?.value||5)){const raw=localStorage.getItem(recordsKey(v));if(!raw)return[];try{const parsed=JSON.parse(raw);return Array.isArray(parsed)?parsed:[];}catch{return[];}}
function saveRecords(records,v=Number(els.mode?.value||5)){localStorage.setItem(recordsKey(v),JSON.stringify(records.slice(0,MAX_RECORDS)));}
const formatRecordDate=iso=>{const stamp=Date.parse(iso||"");return Number.isNaN(stamp)?new Date().toLocaleString("es-ES"):new Date(stamp).toLocaleString("es-ES");};
const normalizeRemoteRecord=record=>({initials:String(record?.initials||"---").slice(0,3).toUpperCase(),score:Number(record?.score||0),mode:String(record?.mode||modeKey()),modeLabel:modeCfg(Number(String(record?.mode||modeKey()).split("x")[0]||5)).label,isoDate:String(record?.createdAt||record?.isoDate||new Date().toISOString()),displayDate:formatRecordDate(record?.createdAt||record?.isoDate),issueNumber:Number(record?.issueNumber||0),replay:null,replayStorage:String(record?.replayStorage||""),hasReplay:Boolean(record?.hasReplay||record?.replayStorage),source:"remote"});
const currentRecords=v=>{const mode=modeKey(v),remote=remoteRecordsCache[mode]||[];return remote.length?remote:loadRecords(v);};
async function workerPost(path,payload){if(!WORKER_API_URL)throw new Error("Falta configurar la URL del worker.");const response=await fetch(`${WORKER_API_URL}${path}`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(payload)});let data={};try{data=await response.json();}catch{}if(!response.ok||data?.error)throw new Error(data?.error||`HTTP ${response.status}`);return data;}
async function loadRemoteRecords(){if(remoteRecordsLoading)return;remoteRecordsLoading=true;try{const modes=Object.keys(MODES).map(v=>`${v}x${v}`),results=await Promise.all(modes.map(async mode=>{try{const data=await workerPost("/records/list",{game:REMOTE_GAME_KEY,mode,category:REMOTE_CATEGORY,limit:REMOTE_RECORD_LIMIT});return [mode,(data.records||[]).map(normalizeRemoteRecord)];}catch{return [mode,[]];}}));remoteRecordsCache=Object.fromEntries(results);remoteRecordsLoaded=true;renderRecords();recordCardOpen&&renderRecordModal();}finally{remoteRecordsLoading=false;}}
function isRecordScore(score,v=Number(els.mode?.value||5)){if(score<=0)return false;const records=currentRecords(v);if(records.length<MAX_RECORDS)return true;return records.some(r=>score>r.score);}
function renderRecordModal(){if(!els.recordModalContent)return;const v=Number(els.mode.value),records=currentRecords(v);if(els.recordModalSubtitle)els.recordModalSubtitle.textContent=`${modeCfg(v).label} · ${remoteRecordsCache[modeKey(v)]?.length?"Global":"Local"}`;els.recordModalContent.innerHTML="";if(!records.length){const empty=document.createElement("div");empty.className="record-card-empty";empty.textContent=remoteRecordsLoaded?"Sin records todavia.":"Cargando records globales...";els.recordModalContent.appendChild(empty);return;}const list=document.createElement("div");list.className="record-card-list";records.forEach((r,i)=>{const row=document.createElement("div");row.className="record-card-row";row.innerHTML=`<span>#${i+1}</span><span>${esc(r.initials)}</span><span>${r.score}</span><span>${esc(r.displayDate)}</span>`;list.appendChild(row);});els.recordModalContent.appendChild(list);}
function setRecordModal(open){recordCardOpen=!!open;els.recordModal?.classList.toggle("hidden",!recordCardOpen);if(recordCardOpen)renderRecordModal();}
async function openRemoteReplay(record,button){if(record.replay){openReplay(record.replay,record);return;}if(!record.issueNumber)return;const previous=button?.textContent||"Ver ronda";button&&(button.disabled=true,button.textContent="Cargando...");try{const data=await workerPost("/records/replay",{game:REMOTE_GAME_KEY,mode:record.mode,issueNumber:record.issueNumber});record.replay=data.replay;openReplay(record.replay,record);}catch(error){setStatus(`No se pudo cargar el replay global: ${error.message||error}.`);}finally{button&&(button.disabled=false,button.textContent=previous);}}
function renderRecordRow(record,index){const row=document.createElement("div");row.className="records-row";row.innerHTML=`<span>${index+1}</span><span>${esc(record.initials)}</span><span>${record.score}</span><span>${esc(record.displayDate)}</span>`;const action=document.createElement("button");action.type="button";action.className="secondary-button record-action-button";const canReplay=Boolean(record.replay)||Boolean(record.issueNumber&&record.hasReplay!==false);action.textContent=canReplay?"Ver ronda":"Sin replay";action.disabled=!canReplay;action.addEventListener("click",()=>{record.source==="remote"&&!record.replay?openRemoteReplay(record,action):openReplay(record.replay,record);});row.appendChild(action);return row;}
function stopTicker(){if(recordsTickerTimer){clearTimeout(recordsTickerTimer);recordsTickerTimer=null;}if(recordsTickerAnimation){recordsTickerAnimation.cancel();recordsTickerAnimation=null;}}
function animateTicker(){if(!els.recordsMiniWindow||!els.recordsMiniTrack)return 3500;const w=Math.max(1,els.recordsMiniWindow.clientWidth),tw=Math.max(1,els.recordsMiniTrack.scrollWidth);els.recordsMiniTrack.style.transform=`translateX(${w}px)`;const duration=Math.max(3200,((w+tw)/50)*1000);recordsTickerAnimation=els.recordsMiniTrack.animate([{transform:`translateX(${w}px)`},{transform:`translateX(${-tw}px)`}],{duration,easing:"linear",fill:"forwards"});return duration;}
function scheduleTicker(){stopTicker();if(!recordsTickerEntries.length){if(els.recordsMiniRank)els.recordsMiniRank.textContent="#1";if(els.recordsMiniText)els.recordsMiniText.textContent="Esperando records...";return;}const entry=recordsTickerEntries[recordsTickerIndex];if(els.recordsMiniRank)els.recordsMiniRank.textContent=`#${recordsTickerIndex+1}`;if(els.recordsMiniText)els.recordsMiniText.textContent=`${entry.initials} ${entry.score} · ${entry.modeLabel}`;const delay=animateTicker()+900;recordsTickerTimer=setTimeout(()=>{recordsTickerIndex=(recordsTickerIndex+1)%recordsTickerEntries.length;scheduleTicker();},delay);}
function renderRecords(){Object.keys(MODES).forEach(v=>{const list=globalRecords[`${v}x${v}`],records=currentRecords(Number(v)),title=list?.closest(".records-mode-group")?.querySelector(".records-mode-title");if(title)title.textContent=MODES[v].label;if(!list)return;list.innerHTML="";if(!records.length){const empty=document.createElement("div");empty.className="records-row records-row-empty";empty.textContent=remoteRecordsLoaded?"Sin records guardados.":"Cargando records...";list.appendChild(empty);return;}records.forEach((r,i)=>list.appendChild(renderRecordRow(r,i)));});recordsTickerEntries=currentRecords(Number(els.mode.value)).slice(0,10);recordsTickerIndex=0;scheduleTicker();}
function openInitials(score,replay){initialsState={active:true,letters:["","",""],slot:0,selectedIndex:0,pendingScore:score,replay};els.initials?.classList.remove("hidden");renderInitials();const deadline=Date.now()+INITIALS_TIMEOUT;if(initialsTimer)clearInterval(initialsTimer);const tick=()=>{const seconds=Math.max(0,Math.ceil((deadline-Date.now())/1000));if(els.initialsTimer)els.initialsTimer.textContent=`00:${String(seconds).padStart(2,"0")}`;if(Date.now()>=deadline)closeInitials(true);};tick();initialsTimer=setInterval(tick,250);}
function maybeOpenInitials(){if(!gameState?.over||gameState.score<=0||gameState.winner!==0||!isRecordScore(gameState.score,Number(els.mode.value)))return;openInitials(gameState.score,{...gameState.replay,finalScore:gameState.score,finishedAt:new Date().toISOString()});}
function renderInitials(){if(!els.initialsSlots||!els.initialsGrid)return;els.initialsSlots.innerHTML="";initialsState.letters.forEach((l,i)=>{const slot=document.createElement("div");slot.className=`initials-slot ${i===initialsState.slot?"is-active":""}`;slot.textContent=l||"_";els.initialsSlots.appendChild(slot);});els.initialsGrid.innerHTML="";letters.forEach((letter,i)=>{const button=document.createElement("button");button.type="button";button.className=`initials-letter ${i===initialsState.selectedIndex?"is-active":""}`;button.textContent=letter;button.addEventListener("click",()=>{initialsState.selectedIndex=i;commitLetter();});els.initialsGrid.appendChild(button);});}
function closeInitials(discard=false){els.initials?.classList.add("hidden");if(initialsTimer){clearInterval(initialsTimer);initialsTimer=null;}if(!discard&&initialsState.letters.every(Boolean))savePendingRecord();initialsState.active=false;}
function commitLetter(){if(!initialsState.active)return;initialsState.letters[initialsState.slot]=letters[initialsState.selectedIndex]||"A";if(initialsState.slot===initialsState.letters.length-1){savePendingRecord();return;}initialsState.slot+=1;renderInitials();}
function deleteLetter(){if(!initialsState.active)return;if(!initialsState.letters[initialsState.slot]&&initialsState.slot>0)initialsState.slot-=1;initialsState.letters[initialsState.slot]="";renderInitials();}
const createReplayId=mode=>`${REMOTE_GAME_KEY}-${mode.replace(/[^a-z0-9]/gi,"").toLowerCase()}-${Date.now()}-${Math.random().toString(36).slice(2,10)}`;
function splitReplayJson(json,size=REMOTE_REPLAY_UPLOAD_CHUNK){const chunks=[];for(let i=0;i<json.length;i+=size)chunks.push(json.slice(i,i+size));return chunks;}
async function uploadReplayIfNeeded(replay,mode){const replayJson=JSON.stringify(replay);if(replayJson.length<=REMOTE_INLINE_REPLAY_LIMIT)return{replay};const replayId=createReplayId(mode),chunks=splitReplayJson(replayJson);for(let i=0;i<chunks.length;i+=1)await workerPost("/replay/upload",{game:REMOTE_GAME_KEY,mode,replayId,partIndex:i,partCount:chunks.length,chunk:chunks[i]});return{replayRef:{storage:"r2",replayId,parts:chunks.length,mode}};}
async function submitGlobalRecord(record){const uploaded=await uploadReplayIfNeeded(record.replay,record.mode),payload={game:REMOTE_GAME_KEY,initials:record.initials,mode:record.mode,category:REMOTE_CATEGORY,score:record.score,isoDate:record.isoDate,...uploaded};await workerPost("/",payload);await loadRemoteRecords();}
function savePendingRecord(){const initials=initialsState.letters.join("").trim();if(initials.length!==3)return;const v=Number(els.mode.value),record={initials,score:initialsState.pendingScore,mode:modeKey(v),modeLabel:modeCfg(v).label,isoDate:new Date().toISOString(),displayDate:new Date().toLocaleString("es-ES"),replay:initialsState.replay,hasReplay:Boolean(initialsState.replay),source:"local"};const records=loadRecords(v);records.push(record);records.sort((a,b)=>b.score-a.score||String(a.isoDate).localeCompare(String(b.isoDate)));saveRecords(records,v);localStorage.setItem(PLAYER_INITIALS_KEY,initials);closeInitials(true);renderRecords();setStatus(`Record guardado para ${initials}. Publicando...`);submitGlobalRecord(record).then(()=>{setStatus(`Record global guardado para ${initials}.`);}).catch(error=>{setStatus(`Record local guardado, pero el global fallo: ${error.message||error}.`);});}
function slots(){const raw=localStorage.getItem(SLOTS_KEY);if(!raw)return Array.from({length:SLOT_COUNT},(_,i)=>({slot:i+1,data:null}));try{const parsed=JSON.parse(raw);return Array.from({length:SLOT_COUNT},(_,i)=>parsed[i]||{slot:i+1,data:null});}catch{return Array.from({length:SLOT_COUNT},(_,i)=>({slot:i+1,data:null}));}}
function saveSlots(arr){localStorage.setItem(SLOTS_KEY,JSON.stringify(arr));}
function renderSlots(){if(!els.slotsList)return;els.slotsList.innerHTML="";slots().forEach((slot,index)=>{const row=document.createElement("div");row.className="save-slot-row";row.innerHTML=`<div class="save-slot-meta"><strong>Slot ${index+1}</strong><small>${slot.data?`${esc(slot.data.modeLabel)} · ${slot.data.score} puntos · ${esc(slot.data.savedAt)}`:"Vacio"}</small></div>`;const actions=document.createElement("div");actions.className="save-slot-actions";const save=document.createElement("button");save.type="button";save.className="secondary-button";save.textContent="Guardar";save.disabled=!gameState||gameState.over;save.addEventListener("click",()=>saveSlot(index));const load=document.createElement("button");load.type="button";load.className="secondary-button";load.textContent="Cargar";load.disabled=!slot.data;load.addEventListener("click",()=>loadSlot(index));const del=document.createElement("button");del.type="button";del.className="danger-button";del.textContent="Borrar";del.disabled=!slot.data;del.addEventListener("click",()=>clearSlot(index));actions.append(save,load,del);row.append(actions);els.slotsList.appendChild(row);});}
function saveSlot(index){if(!gameState||gameState.over)return;const arr=slots();arr[index]={slot:index+1,data:{savedAt:new Date().toLocaleString("es-ES"),modeLabel:gameState.modeLabel,score:gameState.score,state:exportState(gameState),replay:gameState.replay,timerStartedAt:realGameTimerStartedAt}};saveSlots(arr);renderSlots();setStatus(`Partida guardada en slot ${index+1}.`);}
function loadSlot(index){const payload=slots()[index]?.data;if(!payload)return;gameState=importState(payload.state);gameState.replay=payload.replay||gameState.replay;realGameTimerStartedAt=payload.timerStartedAt||Date.now();demoMode=false;attractDismissed=true;awaitingManualStart=false;els.attract?.classList.add("hidden");clearBestBurst();renderAll();persistSession();queueTurn();setStatus(`Slot ${index+1} cargado.`);}
function clearSlot(index){const arr=slots();arr[index]={slot:index+1,data:null};saveSlots(arr);renderSlots();}
function setSlotsOpen(open){saveSlotsOpen=!!open;els.slotsPanel?.classList.toggle("hidden",!saveSlotsOpen);if(saveSlotsOpen)renderSlots();}
function setUndoOpen(open){undoPanelOpen=!!open;els.undoPanel?.classList.toggle("hidden",!undoPanelOpen);}
function serializeSession(){if(!gameState||gameState.over||demoMode)return null;return JSON.stringify({state:exportState(gameState),replay:gameState.replay,timerStartedAt:realGameTimerStartedAt});}
function persistSession(){const payload=serializeSession();payload?localStorage.setItem(SESSION_KEY,payload):clearSession();}
function clearSession(){localStorage.removeItem(SESSION_KEY);}
function restoreSession(){const raw=localStorage.getItem(SESSION_KEY);if(!raw)return false;try{const parsed=JSON.parse(raw);gameState=importState(parsed.state);gameState.replay=parsed.replay||gameState.replay;realGameTimerStartedAt=parsed.timerStartedAt||Date.now();awaitingManualStart=false;attractDismissed=true;els.attract?.classList.add("hidden");demoMode=false;renderAll();queueTurn();return true;}catch{clearSession();return false;}}
function stopReplay(){if(replayTimer){clearTimeout(replayTimer);replayTimer=null;}if(replaySession)replaySession.playing=false;els.replayPlay?.classList.toggle("is-playing",false);}
function renderReplayStep(index){if(!replaySession)return;const snap=replaySession.replay?.snapshots?.[index];if(!snap)return;replaySession.index=index;const state=importState(snap.state);renderBoard(state);if(els.score)els.score.textContent=String(state.score||0);if(els.best)els.best.textContent=String(state.bestScore||0);if(els.replayProgress)els.replayProgress.textContent=`Paso ${index+1} / ${replaySession.replay.snapshots.length}`;if(els.replayModeLabel)els.replayModeLabel.textContent=replaySession.playing?"PLAY":"STOP";if(els.replayMeta)els.replayMeta.textContent=`${replaySession.meta?.initials||"Replay"} · ${replaySession.meta?.score||replaySession.replay.finalScore||0} puntos`;els.replayPlay?.classList.toggle("is-playing",replaySession.playing);}
function replayLoop(){if(!replaySession?.playing)return;replayTimer=setTimeout(()=>{if(!replaySession?.playing)return;const next=replaySession.index+1;if(next>=replaySession.replay.snapshots.length){stopReplay();return;}renderReplayStep(next);replayLoop();},REPLAY_MS);}
function toggleReplay(){if(!replaySession)return;replaySession.playing=!replaySession.playing;renderReplayStep(replaySession.index);if(replaySession.playing)replayLoop();else stopReplay();}
function openReplay(replay,meta={}){if(!replay?.snapshots?.length)return;stopReplay();replayMode=true;replayResumeState=gameState?exportState(gameState):null;els.gameOver?.classList.add("hidden");els.pauseOverlay?.classList.add("hidden");replaySession={replay,meta,index:0,playing:false};els.replayViewer?.classList.remove("hidden");els.replayControls?.classList.remove("hidden");els.replayEmpty?.classList.add("hidden");els.replayIndicator?.classList.remove("hidden");renderReplayStep(0);setStatus("Replay cargada.");}
function closeReplay(){stopReplay();els.replayViewer?.classList.add("hidden");els.replayIndicator?.classList.add("hidden");replayMode=false;if(replayResumeState){gameState=importState(replayResumeState);renderAll();els.gameOver?.classList.toggle("hidden",!gameState.over);els.pauseOverlay?.classList.toggle("hidden",!gamePaused);}replayResumeState=null;replaySession=null;}
async function unlockAudio(){if(!audioContext){const Ctx=window.AudioContext||window.webkitAudioContext;if(Ctx)audioContext=new Ctx();}if(audioContext?.state==="suspended")await audioContext.resume();}
function playTone(kind){if(!audioEnabled||!audioContext)return;const cfg={play:{f:440,d:.06,t:"triangle"},draw:{f:260,d:.07,t:"sine"},special:{f:620,d:.11,t:"square"},uno:{f:820,d:.16,t:"triangle"},win:{f:880,d:.2,t:"triangle"},lose:{f:180,d:.22,t:"sawtooth"}}[kind]||{f:400,d:.08,t:"triangle"},osc=audioContext.createOscillator(),gain=audioContext.createGain(),t=audioContext.currentTime;osc.type=cfg.t;osc.frequency.value=cfg.f;gain.gain.value=.0001;osc.connect(gain);gain.connect(audioContext.destination);gain.gain.exponentialRampToValueAtTime(.04,t+.01);gain.gain.exponentialRampToValueAtTime(.0001,t+cfg.d);osc.start(t);osc.stop(t+cfg.d+.02);}
function updateAudioButton(){if(!els.audio)return;els.audio.textContent=audioEnabled?"🔊 SONIDO ON":"🔈 SONIDO OFF";els.audio.classList.toggle("is-on",audioEnabled);els.audio.setAttribute("aria-pressed",String(audioEnabled));}
function track(){return MUSIC_TRACKS[currentMusicTrackIndex%MUSIC_TRACKS.length]||null;}
function trackUrl(t){return t?new URL(t.file,MUSIC_BASE_URL).toString():"";}
function fmtMusic(ms){const s=Math.max(0,Math.floor(ms/1000)),m=Math.floor(s/60),r=s%60;return`${String(m).padStart(2,"0")}:${String(r).padStart(2,"0")}`;}
function stopMusicTimer(){if(musicTimerInterval){clearInterval(musicTimerInterval);musicTimerInterval=null;}}
function renderMusic(){const t=track();if(els.musicName)els.musicName.textContent=t?.name||"Sin pista";if(els.musicTimer){const em=musicAudioElement?Math.round((musicAudioElement.currentTime||0)*1000):0,dm=musicAudioElement&&Number.isFinite(musicAudioElement.duration)?Math.round(musicAudioElement.duration*1000):0;els.musicTimer.textContent=`${fmtMusic(em)} / ${fmtMusic(dm)}`;}if(els.musicVol)els.musicVol.value=String(musicVolume);if(els.music){els.music.textContent=musicEnabled?"♫ MUSICA ON":"♫ MUSICA OFF";els.music.classList.toggle("is-on",musicEnabled);els.music.setAttribute("aria-pressed",String(musicEnabled));}}
function updateMusicGain(){if(musicAudioElement)musicAudioElement.volume=musicEnabled?musicVolume/100:0;}
function ensureMusic(){if(musicAudioElement)return musicAudioElement;musicAudioElement=new Audio();musicAudioElement.preload="auto";musicAudioElement.addEventListener("loadedmetadata",renderMusic);musicAudioElement.addEventListener("timeupdate",renderMusic);musicAudioElement.addEventListener("play",()=>{stopMusicTimer();musicTimerInterval=setInterval(renderMusic,250);renderMusic();});musicAudioElement.addEventListener("pause",()=>{stopMusicTimer();renderMusic();});musicAudioElement.addEventListener("ended",()=>{stopMusicTimer();if(musicLoopTimeout)clearTimeout(musicLoopTimeout);musicLoopTimeout=setTimeout(()=>{currentMusicTrackIndex=(currentMusicTrackIndex+1)%MUSIC_TRACKS.length;localStorage.setItem(MUSIC_TRACK_KEY,String(currentMusicTrackIndex));startMusic(true);},5000);});updateMusicGain();return musicAudioElement;}
function startMusic(restart=false){if(!musicEnabled)return;const audio=ensureMusic(),t=track(),url=trackUrl(t);if(restart||audio.src!==url){audio.src=url;audio.load();}updateMusicGain();audio.play().catch(()=>renderMusic());renderMusic();}
function stopMusic(){if(musicLoopTimeout){clearTimeout(musicLoopTimeout);musicLoopTimeout=null;}musicAudioElement?.pause();stopMusicTimer();renderMusic();}
function toggleMusic(){musicEnabled=!musicEnabled;localStorage.setItem(MUSIC_KEY,String(musicEnabled));musicEnabled?startMusic(false):stopMusic();renderMusic();}
function prevTrack(){currentMusicTrackIndex=(currentMusicTrackIndex-1+MUSIC_TRACKS.length)%MUSIC_TRACKS.length;localStorage.setItem(MUSIC_TRACK_KEY,String(currentMusicTrackIndex));musicEnabled&&startMusic(true);renderMusic();}
function nextTrack(){currentMusicTrackIndex=(currentMusicTrackIndex+1)%MUSIC_TRACKS.length;localStorage.setItem(MUSIC_TRACK_KEY,String(currentMusicTrackIndex));musicEnabled&&startMusic(true);renderMusic();}
function setMusicVolume(v){musicVolume=clamp(v,0,100);localStorage.setItem(MUSIC_VOL_KEY,String(musicVolume));updateMusicGain();renderMusic();}
function applyTheme(theme){document.body.dataset.theme=theme;localStorage.setItem(THEME_KEY,theme);}
function enterManual(){awaitingManualStart=true;demoMode=false;stopTimer();gameState=initialState(Number(els.mode.value));gameState.journalEntries=[];gameState.undoHistory=[];gameState.replay.snapshots=[];renderAll();els.manual?.classList.remove("hidden");setStatus("Pulsa Nueva ronda para repartir cartas.");}
function startGame({demo=false}={}){gameSessionId+=1;demoMode=demo;awaitingManualStart=false;clearBestBurst();els.pauseOverlay?.classList.add("hidden");els.gameOver?.classList.add("hidden");closeReplay();closeInitials(true);stopReplay();gameState=initialState(Number(els.mode.value));addJournal(`Mesa ${gameState.modeLabel} preparada. Carta inicial: ${cardLabel(gameState.currentCard)} ${colorLabel(gameState.currentColor)}.`,"accent");addReplay("Mesa inicial");startTimer();renderAll();if(!demoMode)clearSession();queueTurn();}
function startAttract(){attractDismissed=false;awaitingManualStart=false;els.attract?.classList.remove("hidden");startGame({demo:true});}
function startActual(){attractDismissed=true;els.attract?.classList.add("hidden");els.manual?.classList.add("hidden");startGame({demo:false});}
function toggleRecords(){const open=els.recordsPanel?.classList.contains("records-panel-collapsed");els.recordsPanel?.classList.toggle("records-panel-collapsed",!open);if(els.toggleRecords)els.toggleRecords.textContent=open?"Ocultar records":"Mostrar records";}
function handleKeys(event){if(initialsState.active){if(event.key==="ArrowRight"){initialsState.selectedIndex=(initialsState.selectedIndex+1)%letters.length;renderInitials();event.preventDefault();}else if(event.key==="ArrowLeft"){initialsState.selectedIndex=(initialsState.selectedIndex-1+letters.length)%letters.length;renderInitials();event.preventDefault();}else if(event.key==="Enter"||event.key===" "){commitLetter();event.preventDefault();}else if(event.key==="Backspace"){deleteLetter();event.preventDefault();}return;}if(!attractDismissed&&(event.key==="Enter"||event.key===" ")){startActual();event.preventDefault();return;}if(event.key.toLowerCase()==="p"){togglePause();event.preventDefault();return;}if(replayMode){if(event.key==="ArrowRight")replaySession&&renderReplayStep(clamp(replaySession.index+1,0,replaySession.replay.snapshots.length-1));else if(event.key==="ArrowLeft")replaySession&&renderReplayStep(clamp(replaySession.index-1,0,replaySession.replay.snapshots.length-1));else if(event.key===" "){toggleReplay();event.preventDefault();}return;}if(gameState?.turnIndex===0&&!gameState.over&&!gamePaused&&!demoMode){const hand=gameState.players[0].hand;if(event.key>="1"&&event.key<="9"){const card=hand[Number(event.key)-1];if(card&&isPlayable(card)){pushUndo(`Antes de jugar ${cardLabel(card)}`);playCard(0,card.id);}}if(event.key===" "){gameState.drawnThisTurn?passTurn():drawHuman();event.preventDefault();}}}
els.startAttract?.addEventListener("click",startActual);els.restart?.addEventListener("click",()=>{els.manual?.classList.add("hidden");startActual();});els.finish?.addEventListener("click",()=>{if(!gameState||gameState.over||replayMode||demoMode||currentPlayer().bot)return;gameState.drawnThisTurn?passTurn():drawHuman();});els.pause?.addEventListener("click",togglePause);els.theme?.addEventListener("change",e=>applyTheme(e.target.value));els.mode?.addEventListener("change",()=>{enterManual();renderRecords();loadRemoteRecords();});els.audio?.addEventListener("click",async()=>{await unlockAudio();audioEnabled=!audioEnabled;localStorage.setItem(AUDIO_KEY,String(audioEnabled));updateAudioButton();});els.music?.addEventListener("click",async()=>{await unlockAudio();toggleMusic();});els.musicPrev?.addEventListener("click",prevTrack);els.musicNext?.addEventListener("click",nextTrack);els.musicVol?.addEventListener("input",e=>setMusicVolume(Number(e.target.value)));els.undoToggle?.addEventListener("click",()=>setUndoOpen(!undoPanelOpen));els.closeUndo?.addEventListener("click",()=>setUndoOpen(false));els.saveButton?.addEventListener("click",()=>setSlotsOpen(!saveSlotsOpen));els.closeSlots?.addEventListener("click",()=>setSlotsOpen(false));els.showStats?.addEventListener("click",()=>{statsPanelOpen=!statsPanelOpen;els.stats?.classList.toggle("hidden",!statsPanelOpen);renderStats();});els.closeStats?.addEventListener("click",()=>{statsPanelOpen=false;els.stats?.classList.add("hidden");});els.shareStats?.addEventListener("click",()=>{els.shareText&&(els.shareText.value=buildStatsText());els.shareModal?.classList.remove("hidden");});els.closeShare?.addEventListener("click",()=>els.shareModal?.classList.add("hidden"));els.shareCopy?.addEventListener("click",async()=>{await navigator.clipboard.writeText(buildStatsText());setStatus("Informe copiado al portapapeles.");});els.shareDownload?.addEventListener("click",()=>{const blob=new Blob([buildStatsText()],{type:"text/plain;charset=utf-8"}),url=URL.createObjectURL(blob),a=document.createElement("a");a.href=url;a.download=`uno-angeloso-estadisticas-${Date.now()}.txt`;a.click();URL.revokeObjectURL(url);});els.shareEmail?.addEventListener("click",()=>{const subject=encodeURIComponent(`Estadisticas Finales UNO Angeloso - ${gameState.modeLabel}`),body=encodeURIComponent(buildStatsText());window.location.href=`mailto:?subject=${subject}&body=${body}`;});els.toggleRecords?.addEventListener("click",toggleRecords);els.bestCard?.addEventListener("click",()=>setRecordModal(!recordCardOpen));els.closeRecordModal?.addEventListener("click",()=>setRecordModal(false));els.selectLetter?.addEventListener("click",commitLetter);els.deleteLetter?.addEventListener("click",deleteLetter);els.closeInitials?.addEventListener("click",()=>closeInitials(true));els.closeReplay?.addEventListener("click",closeReplay);els.replayPlay?.addEventListener("click",toggleReplay);els.replayFirst?.addEventListener("click",()=>replaySession&&renderReplayStep(0));els.replayPrev?.addEventListener("click",()=>replaySession&&renderReplayStep(clamp(replaySession.index-1,0,replaySession.replay.snapshots.length-1)));els.replayNext?.addEventListener("click",()=>replaySession&&renderReplayStep(clamp(replaySession.index+1,0,replaySession.replay.snapshots.length-1)));els.replayLast?.addEventListener("click",()=>replaySession&&renderReplayStep(replaySession.replay.snapshots.length-1));document.addEventListener("keydown",handleKeys);document.addEventListener("pointerdown",()=>{(audioEnabled||musicEnabled)&&unlockAudio();},{once:true});
applyTheme(localStorage.getItem(THEME_KEY)||els.theme?.value||"crt");if(els.theme)els.theme.value=localStorage.getItem(THEME_KEY)||els.theme.value;updateAudioButton();renderMusic();musicEnabled&&startMusic(false);renderSlots();renderRecords();loadRemoteRecords();if(!restoreSession()){enterManual();startAttract();}
